// CleaningJobs sheet has 'status' (not cleaningStatus). Keep only PENDING, no cleaner assigned, no event yet, processingFlag empty (row-level lock).
const items = $input.all();
const filtered = items.filter(item => {
  const j = item.json || {};
  const status = (j.status ?? '').toString().trim();
  const cleanerId = (j.cleanerId ?? '').toString().trim();
  const hasEvent = (j.calendarEventId ?? '').toString().trim() !== '';
  const processingFlag = (j.processingFlag ?? '').toString().trim();
  return status === 'PENDING' && cleanerId === '' && !hasEvent && processingFlag === '';
});
return filtered;

// Attach CleanersProfile data to each job so Assign Cleaner can use it inside the loop (no $('Read CleanersProfile') in loop).
let profile = [];
try {
  const node = $('Read CleanersProfile');
  if (node && typeof node.all === 'function') profile = node.all();
} catch (_) {}
const items = $input.all();
return items.map(item => ({ json: { ...item.json, _cleanersProfile: Array.isArray(profile) ? profile : [] } }));

// If Lookup returned 0 rows or empty row, use job only with fallbacks. Otherwise use first lookup row.
// propertyName: use reservation lookup first; else get from CleanersProfile row matching propertyUid (column may be 'propertyName ' with space); else fallback to propertyUid.
const job = $('Split In Batches').last().json;
const items = $input.all();
const hasReservation = items.length > 0 && items[0].json?.bookingUid;
const lookup = hasReservation ? items[0].json : {};
let propertyName = (lookup.propertyName ?? '').toString().trim();
if (!propertyName && Array.isArray(job._cleanersProfile)) {
  const pu = (job.propertyUid ?? '').toString().trim();
  const profileRow = job._cleanersProfile.find(r => {
    const j = r?.json ?? r;
    const uid = (j?.propertyUid ?? j?.['property UID'] ?? '').toString().trim();
    return uid && uid === pu;
  });
  if (profileRow) {
    const j = profileRow?.json ?? profileRow;
    propertyName = (j?.['propertyName '] ?? j?.propertyName ?? '').toString().trim();
  }
}
if (!propertyName) propertyName = (job.propertyUid ?? '').toString().trim();
const merged = { ...job, ...lookup, propertyName, address: lookup.address ?? job.address ?? 'Address TBD' };
return [{ json: merged }];

// Merge cleaning job (from Split In Batches) with reservation (from Ensure One Item).
const job = $('Split In Batches').last().json;
const lookup = $input.first().json;
const merged = { ...job, ...lookup };
return [{ json: merged }];

// STEP 2 — Assign cleaner by propertyUid using CleanersProfile data attached before the loop. Columns: property UID, cleaner ID, calendar ID, email, name, contact.
const item = $input.first().json;
const propertyUid = (item.propertyUid ?? '').toString().trim();
const rows = Array.isArray(item._cleanersProfile) ? item._cleanersProfile : [];
if (rows.length === 0) throw new Error('No CleanersProfile data on item. Ensure Attach CleanersProfile node runs before Split In Batches and Read CleanersProfile has rows.');
const get = (row, ...keys) => { const j = row && (row.json !== undefined ? row.json : row); if (!j || typeof j !== 'object') return ''; for (const k of keys) { const v = j[k]; if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim(); } return ''; };
const mapping = rows.find(r => {
  const uid = get(r, 'property UID', 'propertyUid');
  return uid && uid === propertyUid;
});
if (!mapping) {
  throw new Error(`No cleaner for propertyUid: ${propertyUid}. Add a row in CleanersProfile with property UID = ${propertyUid}.`);
}
const cleanerId = get(mapping, 'cleaner ID', 'cleanerId');
const email = get(mapping, 'email');
const calendarId = get(mapping, 'calendar ID', 'calendarId');
if (!cleanerId) throw new Error(`CleanersProfile row for ${propertyUid} has no cleaner ID.`);
const assignedAt = new Date().toISOString();
const propertyNameFromProfile = get(mapping, 'propertyName ', 'propertyName');
const out = { ...item, cleanerId, cleanerEmail: email || item.cleanerEmail, cleanerCalendarId: calendarId || item.cleanerCalendarId, cleanerName: get(mapping, 'name'), cleanerContact: get(mapping, 'contact'), assignedAt, status: 'ASSIGNED', propertyName: propertyNameFromProfile || item.propertyName || item.propertyUid };
delete out._cleanersProfile;
return [{ json: out }];

// Form prefilled link constants for Cleaner Clock-In form.
const FORM_ID_HERE = '1FAIpQLSdN-PdIbE1d7ckJ1D7D-EM--sOyjMkUvBP5zFRbj__uM3l59w';
const ENTRY_BOOKING_UID_HERE = 'entry.1708588644';
const ENTRY_CLEANER_ID_HERE = 'entry.1912154425';

const bookingUid = $json.bookingUid;
const cleanerId = $json.cleanerId;
const baseUrl = 'https://docs.google.com/forms/d/e/' + FORM_ID_HERE + '/viewform';
const bookingParam = ENTRY_BOOKING_UID_HERE + '=' + encodeURIComponent(bookingUid || '');
const cleanerParam = ENTRY_CLEANER_ID_HERE + '=' + encodeURIComponent(cleanerId || '');
const clockInLink = baseUrl + '?' + bookingParam + '&' + cleanerParam;
return [{ json: { ...$input.first().json, clockInLink } }];

// Strict UTC only. Use scheduledCleaningTimeUTC from the original job (Split In Batches), not from trimmed update output.
// No 11:00 logic, no cleaningDate/checkOut fallbacks.
const DURATION_HOURS = 3;
// Always pull the full job (with scheduledCleaningTimeUTC) from Split In Batches.
const job = (() => {
  try {
    const n = $('Split In Batches');
    if (n && typeof n.last === 'function') {
      const v = n.last().json;
      if (v && typeof v === 'object') return v;
    }
  } catch (_) {}
  const current = $input.first()?.json;
  return current && typeof current === 'object' ? current : {};
})();
const startTime = job.scheduledCleaningTimeUTC;
if (!startTime || typeof startTime !== 'string' || startTime.trim() === '')
  throw new Error('Missing scheduledCleaningTimeUTC');
const startDate = new Date(startTime.trim());
if (isNaN(startDate.getTime()))
  throw new Error('Invalid scheduledCleaningTimeUTC');
const endDate = new Date(startDate.getTime() + DURATION_HOURS * 3600 * 1000);
const endTime = endDate.toISOString();
// Merge timing fields back onto the latest item in the chain so downstream nodes see them.
const base = $input.first()?.json || job;
return [{ json: { ...base, startTime: startTime.trim(), endTime, durationHours: DURATION_HOURS } }];

